import './Card.scss';

import React, { forwardRef } from 'react';

import { classNames } from '../../helpers/classnames';
import type { CardProps } from './Card.types';

export const Card = forwardRef<HTMLDivElement, CardProps>(({ border, elevation, className, ...props }, ref) => (
	<div
		data-testid="Card"
		className={classNames(
			'dsb_card dsb_card-root',
			`dsb_card__border-${border}`,
			`dsb_card__elevation-${elevation}`,
			className,
		)}
		{...props}
		ref={ref}
	/>
));
